# 1. Enforce phishing-resistant MFA (Passkeys or FIDO2) for all MSP users
# via Conditional Access (in MSP tenant)
az rest --method POST   --url "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies"   --body '{
    "displayName": "Require FIDO2 for Lighthouse users",
    "state": "enabled",
    "conditions": {
      "users": {"includeGroups": ["<MSP_LIGHTHOUSE_USERS_GROUP_OID>"]},
      "applications": {"includeApplications": ["All"]}
    },
    "grantControls": {
      "operator": "OR",
      "authenticationStrength": {"id": "00000000-0000-0000-0000-000000000004"}
    }
  }'

# 2. Enable Access Reviews for Lighthouse authorization groups (Entra ID Governance)
az rest --method POST   --url "https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions"   --body '{
    "displayName": "Quarterly Lighthouse Access Review",
    "reviewers": [{"query": "/v1.0/users/<MSP_SECURITY_ADMIN_OID>", "queryType": "MicrosoftGraph"}],
    "scope": {"query": "/v1.0/groups/<MSP_LIGHTHOUSE_ENGINEERS_GROUP_OID>/members", "queryType": "MicrosoftGraph"},
    "settings": {"justificationRequiredOnApproval": true, "defaultDecision": "Deny",
                  "recurrence": {"pattern": {"type": "absoluteMonthly", "interval": 3}, "range": {"type": "noEnd"}}}
  }'

# 3. Privileged Identity Management: ensure no permanent Contributor in Lighthouse groups
az pim eligible-assignment list   --group-id <MSP_LIGHTHOUSE_ENGINEERS_GROUP_OID>   --query "[?properties.memberType!='Direct'].{principal:properties.expandedProperties.principal.displayName, role:properties.expandedProperties.roleDefinition.displayName}"

# 4. Monitor for unusual MSP authentication patterns in Entra Sign-In Logs
# (MSP tenant Log Analytics workspace)
# SigninLogs
# | where UserPrincipalName in (lighthouse_user_list)
# | where AuthenticationRequirement != "multiFactorAuthentication"
#     or RiskLevelDuringSignIn in ("medium","high")
# | project TimeGenerated, UserPrincipalName, AppDisplayName, IPAddress, RiskLevelDuringSignIn
# | order by TimeGenerated desc
